<template><SiteLayout><section class="mx-auto max-w-7xl px-4 py-14"><h1 class="text-4xl font-black">Premium Training</h1><p class="mt-3 text-slate-600">Valid donations: GHS 50-100 or USD 5-10.</p><div class="mt-6 rounded bg-slate-950 p-5 text-white"><select v-model="currency" class="field"><option>GHS</option><option>USD</option></select><input v-model.number="amount" class="field mt-3" type="number"><p class="mt-3 rounded p-3 font-bold" :class="validClass">{{ validation }}</p></div><div class="mt-8 grid gap-5 md:grid-cols-3"><article v-for="course in courses" :key="course.title" class="rounded border bg-white p-6"><h2 class="text-xl font-black">{{ course.title }}</h2><p class="mt-3 text-slate-600">{{ course.summary }}</p><button class="mt-5 rounded bg-emerald-700 px-4 py-2 font-bold text-white" @click="unlock(course)">Donate & Enroll</button></article></div><p v-if="message" class="mt-5 rounded bg-emerald-50 p-3 font-bold text-emerald-900">{{ message }}</p><p v-if="error" class="mt-5 rounded bg-red-50 p-3 font-bold text-red-800">{{ error }}</p></section></SiteLayout></template>
<script setup lang="ts">import { computed, onMounted, ref } from 'vue';import SiteLayout from '../components/SiteLayout.vue';import { premiumCourses } from '../data/siteContent';import { fetchCourses } from '../services/courseService';import { createDemoDonation } from '../services/paymentService';const amount=ref(50);const currency=ref<'GHS'|'USD'>('GHS');const courses=ref<any[]>(premiumCourses);const message=ref('');const error=ref('');const ghs=computed(()=>currency.value==='GHS'?amount.value:amount.value*10);const validation=computed(()=>ghs.value<50?'Denied: below minimum':ghs.value>100?'Error: above maximum':'Valid donation amount');const validClass=computed(()=>ghs.value<50?'bg-red-100 text-red-800':ghs.value>100?'bg-amber-100 text-amber-900':'bg-emerald-100 text-emerald-900');onMounted(async()=>{try{const live=await fetchCourses();courses.value=live.filter(c=>c.isPremium).map(c=>({id:c.id,title:c.title,summary:c.description||'Premium cybersecurity course.'}));}catch{}});async function unlock(course:any){message.value='';error.value='';const token=localStorage.getItem('yckf_token');if(!token){error.value='Login as student first.';return}try{await createDemoDonation(token,{courseId:course.id,amount:amount.value,currency:currency.value});message.value=`${course.title} unlocked.`}catch(e:any){error.value=e.message}}</script><style scoped>.field{display:block;width:100%;border:1px solid #334155;border-radius:.375rem;background:#0f172a;padding:.8rem}</style>
